window.vocalMp4BuildPrompt = function buildPrompt(candidate) {
	const { id, labels } = candidate;
	const avoidanceWords = (candidate.lyricAvoidance?.words || []).filter((item) => item.word && (item.total > 0 || item.watch)).slice(0, 10);
	const avoidanceLines = avoidanceWords.length ? [
		"",
		`既存曲の歌詞で使いすぎている語: ${avoidanceWords.map((item) => item.word).join("、")}`,
		"上の語や近い言い換えを歌詞に安易に入れない。同じ比喩や香りの語に頼らず、今回のテーマ固有の名詞、動き、感情で差別化する。"
	] : [];
	return [
		`ID: ${id}`,
		"",
		`リクエスト: ${labels.request.name}`,
		`雰囲気: ${labels.mood.name}`,
		`中心となる楽器: ${labels.instrument.name}`,
		`テーマ: ${labels.theme.name}`,
		"",
		"世界観はアラビアンナイト風のファンタジー世界であり、",
		"現代的な高層ビルや機械文明の雰囲気にはしない。",
		"",
		"華奢で可憐な若い女性による日本語ボーカル。",
		"ただし、添付画像の女性の容姿や服装は歌詞に組み込まないこと。",
		"またジャケット画像にもタイトル以外のテキスト情報を一切組み込まないこと。",
		"ジャケット画像はゲーム画面でも使用するため、主人公の女性のダイナミックなアングルやポーズを強調した構図にする。",
		"ただし、服装や装飾は極端に変えず、吟遊詩人やシャーマンを思わせる神秘的で美しい画像にする。",
		"",
		"音ゲー向けの明確なリズムと、平坦にならない展開にする。",
		`${labels.instrument.name}を明確に聞かせる。`,
		"無音区間は作らない。",
		"長さは85〜95秒。",
		"単調にならないように安易な歌詞の繰り返しはしない。",
		"るる、をを、といった日本語として意味不明になる1音の繰り返しは無闇にしない。",
		"盛り上がりの途中で切らず、自然に完結させる。",
		"",
		"楽曲タイトルはひらがなのみにしない。",
		"歌詞が単調にならないように、テーマ固有の出来事、場所、感情、動作から具体的なキーワードを２つ歌詞創作のヒントに追加する。汎用的な香りや質感の語に頼らない。",
		...avoidanceLines,
		"歌詞は聞き取りやすく自然な日本語とし、「は」「へ」の発音は特に気をつけ、極力使用を避ける。",
		"歌詞本文はひらがなのみとし、漢字、カタカナ、「、」「。」は使わない。"
	].join("\n");
};
